diff --git a/middleware/url_format.go b/middleware/url_format.go
index abc123..def456 100644
--- a/middleware/url_format.go
+++ b/middleware/url_format.go
@@ -62,6 +62,19 @@ func URLFormat(next http.Handler) http.Handler {
 				if rctx != nil {
 					rctx.RoutePath = path[:idx]
 				}
+
+				r = r.Clone(r.Context())
+				r.URL.Path = path[:idx]
+				if r.URL.RawPath != "" {
+					rawBase := strings.LastIndex(r.URL.RawPath, "/")
+					rawIdx := strings.LastIndex(r.URL.RawPath[rawBase:], ".")
+					if rawIdx > 0 {
+						r.URL.RawPath = r.URL.RawPath[:rawBase+rawIdx]
+					}
+				}
 			}
 		}
